import{_ as r,I as s,o as l,c as d,j as t,a,J as c,ap as n,t as h}from"./chunks/framework.ockA5sXJ.js";const w=JSON.parse('{"title":"Preview channel","description":"How breaking changes ship behind the Citizen preview channel","frontmatter":{"title":"Preview channel","description":"How breaking changes ship behind the Citizen preview channel"},"headers":[],"relativePath":"contribute/preview-channel.md","filePath":"contribute/preview-channel.md","lastUpdated":1783490799000}'),p={name:"contribute/preview-channel.md"};function u(i,e,g,m,v,f){const o=s("CopyOrDownloadAsMarkdownButtons");return l(),d("div",null,[e[6]||(e[6]=t("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /mediawiki-skins-Citizen/contribute/preview-channel.md for this page in Markdown format",-1)),e[7]||(e[7]=t("h1",{id:"preview-channel",tabindex:"-1"},[a("Preview channel "),t("a",{class:"header-anchor",href:"#preview-channel","aria-label":"Permalink to “Preview channel”"},"​")],-1)),c(o),e[8]||(e[8]=n('<p>Citizen avoids breaking changes. The rare unavoidable ones — changes that alter defaults, markup, tokens, or config semantics for existing wikis — ship behind the <strong>preview channel</strong> until the next major release. The channel is a pressure valve, never a justification: anything that works in both worlds ships normally and is never gated. The valve exists because Citizen ships a major only alongside a MediaWiki LTS release, roughly every two years. Without the channel, breaking work would either sit unmerged for most of a cycle or force an off-cadence major; with it, the work lands on <code>main</code> early, admins can rehearse it, and stable users stay untouched.</p><p>Every request resolves to <em>stable</em> or <em>preview</em> exactly once, in <code>PreviewChannel::isPreview()</code> (applied by <code>SkinHooks::applyPreviewChannel()</code>). Precedence: URL param &gt; cookie &gt; <code>$wgCitizenPreview</code>, with the deprecated alias as a second opt-in signal. Preview requests get the <code>citizen-v4</code> generation class on <code>&lt;html&gt;</code>; the class stays through all of 4.x — so admin CSS guarded on it survives the flip — and is removed in 5.0. Admins&#39; view of all this lives in the <a href="./../guide/migrating-to-citizen-4">Migrating to Citizen 4 guide</a>.</p><h2 id="vocabulary-—-two-greppable-markers" tabindex="-1">Vocabulary — two greppable markers <a class="header-anchor" href="#vocabulary-—-two-greppable-markers" aria-label="Permalink to “Vocabulary — two greppable markers”">​</a></h2>',3)),t("ul",null,[e[5]||(e[5]=t("li",null,[t("strong",null,[a("New-world code references "),t("code",null,"citizen-v4")]),a(" — a selector, a template-data key, a condition, or a "),t("code",null,"classList"),a(" check. The reference itself is the marker. One exception: the "),t("code",null,"is-v4"),a(" template-data key doesn't contain the literal class name, so the flip sweep greps for it separately.")],-1)),t("li",null,[e[0]||(e[0]=t("strong",null,[a("Legacy-side code that dies at the flip carries a "),t("code",null,"citizen-v4-remove"),a(" comment")],-1)),e[1]||(e[1]=a(" — ",-1)),e[2]||(e[2]=t("code",null,"// citizen-v4-remove",-1)),e[3]||(e[3]=a(" (LESS/PHP/JS) or ",-1)),t("code",null,h(!i.citizen-i.v4-i.remove),1),e[4]||(e[4]=a(" (Mustache). Some marked sites are cleaned up before the flip; their tracking issue lists them explicitly. Early cleanup is issue-driven; the flip grep is the backstop.",-1))])]),e[9]||(e[9]=n('<p><code>skin.json</code> cannot carry comments — its flip steps are enumerated in the runbook below instead.</p><h2 id="per-surface-conventions" tabindex="-1">Per-surface conventions <a class="header-anchor" href="#per-surface-conventions" aria-label="Permalink to “Per-surface conventions”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Surface</th><th style="text-align:left;">Convention</th></tr></thead><tbody><tr><td style="text-align:left;">CSS, large surface</td><td style="text-align:left;">Separate ResourceLoader module; the hook loads exactly one per request (the token-module pattern) — for whole-stylesheet surfaces; when in doubt, start with a co-located guard block and promote if it grows.</td></tr><tr><td style="text-align:left;">CSS, small delta</td><td style="text-align:left;">Co-located <code>:root.citizen-v4 &amp;</code> block in the component&#39;s LESS file (the guard-block pattern); the legacy block it replaces carries the remove marker.</td></tr><tr><td style="text-align:left;">Extension <code>skinStyles/</code></td><td style="text-align:left;">Guard-block pattern only — skinStyles attach to the extension&#39;s modules and cannot be swapped per-request.</td></tr><tr><td style="text-align:left;">PHP</td><td style="text-align:left;">Consume the resolved value; never re-read the config/cookie/URL elsewhere. Legacy branches carry the remove marker.</td></tr><tr><td style="text-align:left;">Mustache / markup</td><td style="text-align:left;">Prefer additive markup both worlds can style. Genuine forks use an <code>is-v4</code> template-data boolean; the legacy branch carries the remove marker. Markup forks are the rarest gate — each is a cache-window hazard.</td></tr><tr><td style="text-align:left;">JS</td><td style="text-align:left;"><code>document.documentElement.classList.contains( &#39;citizen-v4&#39; )</code> — the class matches the HTML the page was served with, even from edge caches. When the first internal JS consumer appears, extract this into a shared util.</td></tr></tbody></table><p>Gate CSS on the <strong>class</strong>, never on &quot;did the module load&quot; — the class travels with cached HTML, so styles apply to the generation the page was rendered in.</p><h2 id="policy" tabindex="-1">Policy <a class="header-anchor" href="#policy" aria-label="Permalink to “Policy”">​</a></h2><ul><li>Gated work ships production-quality: it reaches early-adopter production wikis through ordinary minor releases.</li><li>Shape may evolve during the cycle; every gated user-facing changelog entry carries a &quot;(preview)&quot; suffix in the commit subject.</li><li>Preview-only config values and preference options degrade gracefully under stable: documented fallback, hidden UI.</li><li>Docs pages for preview-only features open with a <code>::: warning Preview (Citizen 4)</code> container stating the feature becomes the default in 4.0.</li><li>Testing: no doubled CI matrix. The resolver has a precedence table; wherever behavior forks, that component&#39;s tests cover both sides (Vitest toggles the class on the fixture root; PHPUnit passes both resolved values).</li></ul><h2 id="flip-runbook-per-major-cycle-instantiate-as-a-tracking-issue" tabindex="-1">Flip runbook (per major cycle; instantiate as a tracking issue) <a class="header-anchor" href="#flip-runbook-per-major-cycle-instantiate-as-a-tracking-issue" aria-label="Permalink to “Flip runbook (per major cycle; instantiate as a tracking issue)”">​</a></h2><ol><li>Code sweep: grep <code>citizen-v4</code> → unguard; grep <code>is-v4</code> → collapse template forks; grep <code>citizen-v4-remove</code> → delete.</li><li>Collapse dual-path tests: fork-point tests (resolver precedence rows for the alias, the dual-class and module-choice assertions in <code>SkinHooksTest</code>) reduce to the single surviving behavior; then run the full verification (<code>npm run preflight</code> + <code>composer preflight</code>) before tagging.</li><li>Module name continuity — for each large-surface module the cycle swapped (this cycle: the token pipeline): the stable module name survives with new contents (<code>skins.citizen.tokens</code> becomes the new pipeline); the <code>.new</code> name stays registered as a deprecated <strong>module</strong> alias for one release so edge-cached preview HTML keeps resolving its stylesheet, then dies.</li><li>skin.json: remove the legacy module&#39;s file list, the deprecated <strong>config</strong> alias (<code>$wgCitizenUseNewToken</code>), and their i18n keys (all languages).</li><li>The generation class becomes unconditionally stamped; immediately file its next-major removal issue.</li><li><code>$wgCitizenPreview = &lt;shipped major&gt;</code> goes inert by design — no code change needed; note it in release notes.</li><li>Docs: &quot;Preview (Citizen N)&quot; badges collapse into &quot;since N.0&quot;; the rehearsal guide stays reachable via the versioned docs.</li><li>Release N.0.0 aligned with the MediaWiki LTS bump (<code>requires</code> update in skin.json).</li></ol><h2 id="naming-for-future-cycles" tabindex="-1">Naming for future cycles <a class="header-anchor" href="#naming-for-future-cycles" aria-label="Permalink to “Naming for future cycles”">​</a></h2><p>The switch (<code>$wgCitizenPreview</code>, <code>?citizenpreview=</code>) is permanent. Only the generation class is per-cycle: <code>citizen-v5</code> for the 5.0 cycle, stamped alongside <code>citizen-v4</code> removal.</p>',10))])}const k=r(p,[["render",u]]);export{w as __pageData,k as default};
